SELECT sector, SUM(damage_cost) AS total_damage_cost
FROM weather_event_impacts
GROUP BY sector;

SELECT COUNT(*)
FROM weather_event_impacts
WHERE damage_cost > 2000000;

SELECT DISTINCT ws.station_id, ws.station_name
FROM weather_data wd
JOIN weather_stations ws ON wd.station_id = ws.station_id;

SELECT event_name
FROM weather_events
WHERE start_date < (
    SELECT MIN(year) * 10000 + MIN(month) * 100 + MIN(day)
    FROM weather_data
);
